def test_decode_simple_string():
    """Test decode with a simple ASCII string."""
    source = '{"key":"value"}'
    result = decode(source)
    assert result == '{"key":"value"}'


def test_decode_with_special_chars():
    """Test decode with special characters that need decoding."""
    # Simple test with characters in the range 128-255
    source = '{"time":16501358936120880' + chr(0x0106) + '}'
    result = decode(source)
    # The decode function processes characters based on the algorithm
    assert isinstance(result, int) or isinstance(result, str)


def test_decode_single_char():
    """Test decode with a single character."""
    source = "a"
    result = decode(source)
    assert result == "a"


def test_decode_two_chars():
    """Test decode with two characters."""
    source = "ab"
    result = decode(source)
    assert result == "ab"
